options.getOption:
const s0 = context.panel.data.series[0];
if (!s0 || !s0.fields.length) return {};

const getVals = f => {
  if (!f) return [];
  const v = f.values;
  if (Array.isArray(v)) return v;
  if (typeof v.toArray === 'function') return v.toArray();
  return Array.from(v);
};

const hopArr = getVals(s0.fields.find(f => f.name === 'hop'));
const icpArr = getVals(s0.fields.find(f => f.name === 'icp'));

const fmtICP = v => v >= 1e6 ? (v/1e6).toFixed(2)+'M' : v >= 1000 ? (v/1000).toFixed(0)+'k' : v.toFixed(0);
const COLORS = ['#26a69a', '#4db6ac', '#ffb74d', '#ef5350'];
const LABELS = {
  'Hop 0': 'Hop 0 — direkt',
  'Hop 1': 'Hop 1 — Zwischen',
  'Hop 2': 'Hop 2 — Aggregator',
  'Hop 3': 'Hop 3 — Exchange'
};

return {
  backgroundColor: 'transparent',
  animation: false,
  grid: { left: 120, right: 70, top: 10, bottom: 30 },
  tooltip: {
    trigger: 'axis',
    axisPointer: { type: 'shadow' },
    backgroundColor: 'rgba(20,20,20,0.92)',
    borderColor: '#444',
    textStyle: { color: '#ddd', fontSize: 12 },
    formatter: params => {
      const p = params[0];
      return '<b>' + (LABELS[p.name] || p.name) + '</b><br/>Total: <b>' + fmtICP(p.value) + ' ICP</b>';
    }
  },
  xAxis: {
    type: 'value',
    axisLabel: { color: '#aaa', fontSize: 10, formatter: v => fmtICP(v) },
    splitLine: { lineStyle: { color: '#2a2a2a' } },
    axisLine: { show: false },
    axisTick: { show: false }
  },
  yAxis: {
    type: 'category',
    data: hopArr,
    axisLabel: {
      color: '#aaa', fontSize: 11,
      formatter: v => LABELS[v] || v
    },
    axisLine: { lineStyle: { color: '#555' } },
    axisTick: { show: false },
    splitLine: { show: false }
  },
  series: [{
    type: 'bar',
    barMaxWidth: 28,
    data: icpArr.map((v, i) => ({
      value: v,
      itemStyle: { color: COLORS[i % COLORS.length] },
      label: {
        show: true,
        position: 'right',
        formatter: p => fmtICP(p.value),
        color: '#ccc',
        fontSize: 10
      }
    }))
  }]
};

const s0 = context.panel.data.series[0];  // Tick-Trades
const s1 = context.panel.data.series[1];  // NP→Exchange
const s2 = context.panel.data.series[2];  // FR Flips
const s3 = context.panel.data.series[3];  // Regime-Wechsel
const s4 = context.panel.data.series[4];  // Large Sells
if (!s0 || !s0.fields.length) return {};

const getVals = f => {
  if (!f) return [];
  const v = f.values;
  if (Array.isArray(v)) return v;
  if (typeof v.toArray === 'function') return v.toArray();
  return Array.from(v);
};

// --- Tick-Trades ---
const tsMsArr  = getVals(s0.fields.find(f => f.name === 'ts_ms'));
const priceArr = getVals(s0.fields.find(f => f.name === 'price'));
const qtyArr   = getVals(s0.fields.find(f => f.name === 'qty'));
const bmArr    = getVals(s0.fields.find(f => f.name === 'bm'));
if (!tsMsArr.length) return {};

// --- 200-Tick Kerzen berechnen ---
const TICK_SIZE = 200;
const candles = [];
for (let start = 0; start < tsMsArr.length; start += TICK_SIZE) {
  const end = Math.min(start + TICK_SIZE, tsMsArr.length);
  let high = priceArr[start], low = priceArr[start];
  let buyVol = 0, sellVol = 0;
  for (let j = start; j < end; j++) {
    if (priceArr[j] > high) high = priceArr[j];
    if (priceArr[j] < low)  low  = priceArr[j];
    if (bmArr[j]) sellVol += qtyArr[j];
    else          buyVol  += qtyArr[j];
  }
  candles.push({
    tsMs:       tsMsArr[start],
    tsEnd:      tsMsArr[end - 1],
    open:       priceArr[start],
    high, low,
    close:      priceArr[end - 1],
    buyVol, sellVol,
    tickCount:  end - start,
    durationMs: tsMsArr[end - 1] - tsMsArr[start],
    isLive:     (end - start) < TICK_SIZE
  });
}

// --- NP→Exchange auf Kerzen mappen ---
const npByCandle = new Array(candles.length).fill(0);
if (s1 && s1.fields.length) {
  const npTs  = getVals(s1.fields.find(f => f.name === 'ts_ms'));
  const npAmt = getVals(s1.fields.find(f => f.name === 'amount'));

  for (let i = 0; i < npTs.length; i++) {
    const t = npTs[i];
    if (t < candles[0].tsMs) continue;
    // Binärsuche: letzte Kerze mit tsMs <= t
    let lo = 0, hi = candles.length - 1;
    while (lo < hi) {
      const mid = Math.floor((lo + hi + 1) / 2);
      if (candles[mid].tsMs <= t) lo = mid;
      else hi = mid - 1;
    }
    npByCandle[lo] += npAmt[i];
  }
}

const maxNP = Math.max(...npByCandle.filter(v => v > 0), 1);
// --- CVD (Cumulative Volume Delta) ---
let cvdRunning = 0;
const cvdBase0 = candles.length ? (candles[0].buyVol - candles[0].sellVol) : 0;
const cvd = candles.map(c => { cvdRunning += c.buyVol - c.sellVol; return cvdRunning; });
const cvdOffset = cvd[0] || 0;
const cvdNorm = cvd.map(v => v - cvdOffset);

// --- Large Sells (s4) auf Kerzen mappen ---
const largeSellsByCandle = new Array(candles.length).fill(0);
if (s4 && s4.fields.length) {
  const lsTs  = getVals(s4.fields.find(f => f.name === 'ts_ms'));
  const lsQty = getVals(s4.fields.find(f => f.name === 'qty'));
  for (let i = 0; i < lsTs.length; i++) {
    const t = lsTs[i];
    if (!candles.length || t < candles[0].tsMs) continue;
    let lo = 0, hi = candles.length - 1;
    while (lo < hi) {
      const mid = Math.floor((lo + hi + 1) / 2);
      if (candles[mid].tsMs <= t) lo = mid;
      else hi = mid - 1;
    }
    largeSellsByCandle[lo] += lsQty[i];
  }
}


// --- FR Flip Linien ---
const flipLines = [];
if (s2 && s2.fields.length) {
  const flipTs   = getVals(s2.fields.find(f => f.name === 'ts_ms'));
  const flipType = getVals(s2.fields.find(f => f.name === 'flip_type'));
  for (let i = 0; i < flipTs.length; i++) {
    const t = flipTs[i];
    if (!candles.length || t < candles[0].tsMs) continue;
    let lo = 0, hi = candles.length - 1;
    while (lo < hi) {
      const mid = Math.floor((lo + hi + 1) / 2);
      if (candles[mid].tsMs <= t) lo = mid;
      else hi = mid - 1;
    }
    const isBull = flipType[i] === 'bullish';
    const fcolor  = isBull ? '#26a69a' : '#ef5350';
    flipLines.push({
      name: isBull ? 'FR Flip → Bullish' : 'FR Flip → Bearish',
      xAxis: lo,
      lineStyle: { color: fcolor, width: 1, type: 'dotted', opacity: 0.85 },
      label: {
        show: true,
        position: 'insideEndBottom',
        distance: 4,
        formatter: isBull ? 'FR↑' : 'FR↓',
        color: fcolor,
        fontSize: 9,
        fontWeight: 'bold'
      }
    });
  }
}


// --- Regime Hintergrund ---
const REGIME_COLORS = {
  'KOMPRESSION_STARK':   'rgba(0,230,118,0.13)',
  'KOMPRESSION':         'rgba(38,166,154,0.11)',
  'KOMPRESSION_SCHWACH': 'rgba(139,195,74,0.09)',
  'TRIGGER_BULLISH':     'rgba(255,235,59,0.13)',
  'NEUTRAL':             'rgba(0,0,0,0)',
  'DISTRIBUTION':        'rgba(255,152,0,0.11)',
  'DISTRIBUTION_STARK':  'rgba(255,87,34,0.13)',
  'DISTRIBUTION_TOP':    'rgba(239,83,80,0.16)',
};
const REGIME_LABEL_SHORT = {
  'KOMPRESSION_STARK':   '🟢🟢 Stark',
  'KOMPRESSION':         '🟢 Komp',
  'KOMPRESSION_SCHWACH': '🟡 Komp',
  'TRIGGER_BULLISH':     '⚠️ Trigger',
  'NEUTRAL':             '',
  'DISTRIBUTION':        '🔴 Dist',
  'DISTRIBUTION_STARK':  '🔴🔴 Dist',
  'DISTRIBUTION_TOP':    '🔴🔴 TOP',
};
const REGIME_LABEL_COLOR = {
  'KOMPRESSION_STARK':   '#00e676',
  'KOMPRESSION':         '#4db6ac',
  'KOMPRESSION_SCHWACH': '#aed581',
  'TRIGGER_BULLISH':     '#fff176',
  'NEUTRAL':             'transparent',
  'DISTRIBUTION':        '#ffb74d',
  'DISTRIBUTION_STARK':  '#ff7043',
  'DISTRIBUTION_TOP':    '#ef5350',
};
const regimeAreas = [];
let currentRegime = 'NEUTRAL';
if (s3 && s3.fields.length && candles.length) {
  const rTs  = getVals(s3.fields.find(f => f.name === 'ts_ms'));
  const rReg = getVals(s3.fields.find(f => f.name === 'regime'));
  if (rReg.length > 0) currentRegime = rReg[rReg.length - 1];
  // Hilfsfunktion: Timestamp → nächster Kerzen-Index
  const tsToIdx = t => {
    if (t <= candles[0].tsMs) return 0;
    if (t >= candles[candles.length-1].tsMs) return candles.length - 1;
    let lo = 0, hi = candles.length - 1;
    while (lo < hi) {
      const mid = Math.floor((lo + hi + 1) / 2);
      if (candles[mid].tsMs <= t) lo = mid; else hi = mid - 1;
    }
    return lo;
  };
  for (let i = 0; i < rTs.length; i++) {
    const startIdx = tsToIdx(rTs[i]);
    const endIdx   = i + 1 < rTs.length ? tsToIdx(rTs[i + 1]) : candles.length - 1;
    const color    = REGIME_COLORS[rReg[i]] || 'rgba(0,0,0,0)';
    if (color === 'rgba(0,0,0,0)') continue;  // NEUTRAL: kein Block
    const rLabel = REGIME_LABEL_SHORT[rReg[i]] || '';
    const rColor = REGIME_LABEL_COLOR[rReg[i]] || '#fff';
    regimeAreas.push([
      {
        xAxis: startIdx,
        itemStyle: { color },
        label: {
          show: rLabel !== '' && (endIdx - startIdx) > 2,
          position: 'inside',
          rotate: 90,
          formatter: rLabel,
          color: rColor,
          fontSize: 9,
          fontWeight: 'bold'
        }
      },
      { xAxis: endIdx }
    ]);
  }
}

// --- Labels ---

// Zoom-State als Property auf der Chart-Instanz speichern
// (überlebt Refreshes, weil die ECharts-Instanz dieselbe bleibt)
const chart = context.panel.chart;
let zoomStart = 50, zoomEnd = 100;
if (chart) {
  // Gespeicherten Zoom lesen (von vorherigem Render)
  if (typeof chart.__mmZoomStart !== 'undefined') {
    zoomStart = chart.__mmZoomStart;  // unused
    zoomEnd   = chart.__mmZoomEnd;
  }
  // Listener registrieren der Zoom-Änderungen mitschreibt
  chart.off('datazoom');
  chart.on('datazoom', () => {
    try {
      const opt = chart.getOption();
      if (opt && opt.dataZoom && opt.dataZoom[0]) {
        chart.__mmZoomStart = opt.dataZoom[0].start;
        chart.__mmZoomEnd   = opt.dataZoom[0].end;
      }
    } catch(e) {}
  });
}

const labels = candles.map((c, i) => {
  const d  = new Date(c.tsMs);
  const hm = d.toISOString().slice(11, 16);
  if (i === 0) return d.toISOString().slice(5, 10).replace('-', '.') + ' ' + hm;
  const prev = new Date(candles[i - 1].tsMs);
  if (d.getUTCDate() !== prev.getUTCDate())
    return d.toISOString().slice(5, 10).replace('-', '.') + ' ' + hm;
  return hm;
});

const fmtDur = ms => {
  const s = Math.round(ms / 1000);
  if (s < 60)   return s + 's';
  if (s < 3600) return Math.round(s / 60) + 'min';
  return (s / 3600).toFixed(1) + 'h';
};
const fmtICP = v => v >= 1e6 ? (v/1e6).toFixed(2)+'M' : v >= 1000 ? (v/1000).toFixed(0)+'k' : v.toFixed(0);

const BULL = '#26a69a';
const BEAR = '#ef5350';
const GREY = '#666666';
const NP_COLOR = '#ff9800';

const _curLabel = currentRegime === 'NEUTRAL' ? 'Neutral' : (REGIME_LABEL_SHORT[currentRegime] || currentRegime);
const _curColor = REGIME_LABEL_COLOR[currentRegime] || '#aaa';

return {
  backgroundColor: 'transparent',
  graphic: [{
    type: 'text',
    right: 28,
    top: 14,
    style: {
      text: 'Regime: ' + _curLabel,
      fontSize: 11,
      fontWeight: 'bold',
      fill: _curColor
    }
  }],
  animation: false,
  grid: [
    { left: 70, right: 20, top: 10, bottom: 80 },
    { left: 70, right: 20, top: '72%', bottom: 40 }
  ],
  xAxis: [
    {
      type: 'category', data: labels, gridIndex: 0,
      axisLine: { lineStyle: { color: '#555' } },
      axisLabel: { color: '#aaa', fontSize: 10 },
      axisTick: { show: false }, splitLine: { show: false }, boundaryGap: true
    },
    {
      type: 'category', data: labels, gridIndex: 1,
      axisLabel: { show: false },
      axisLine: { lineStyle: { color: '#555' } },
      axisTick: { show: false }, splitLine: { show: false }, boundaryGap: true
    }
  ],
  yAxis: [
    {
      scale: true, gridIndex: 0,
      axisLabel: { color: '#aaa', fontSize: 11, formatter: v => v.toFixed(3) },
      splitLine: { lineStyle: { color: '#2a2a2a' } },
      axisLine: { show: false }, axisTick: { show: false }
    },
    {
      scale: true, gridIndex: 1,
      axisLabel: { color: '#aaa', fontSize: 10,
        formatter: v => (Math.abs(v)/1000).toFixed(0) + 'k' },
      splitLine: { show: false }, axisLine: { show: false }, axisTick: { show: false },
      splitNumber: 2
    },
    {
      scale: true, gridIndex: 1, position: 'right',
      axisLabel: { color: '#7986cb', fontSize: 9,
        formatter: v => { const a = Math.abs(v); return (a >= 1000 ? (v/1000).toFixed(0)+'k' : v.toFixed(0)); } },
      splitLine: { show: false }, axisLine: { show: false }, axisTick: { show: false },
      splitNumber: 3
    }
  ],
  dataZoom: [
    { type: 'inside', xAxisIndex: [0, 1], start: 0, end: 100 },
    {
      type: 'slider', xAxisIndex: [0, 1], bottom: 5, height: 25,
      start: 0, end: 100,
      textStyle: { color: '#888' }, borderColor: '#444',
      fillerColor: 'rgba(80,80,80,0.3)',
      handleStyle: { color: '#777', borderColor: '#555' }
    }
  ],
  tooltip: {
    trigger: 'axis',
    axisPointer: { type: 'cross', crossStyle: { color: '#555' } },
    backgroundColor: 'rgba(20,20,20,0.92)',
    borderColor: '#444',
    textStyle: { color: '#ddd', fontSize: 12 },
    formatter: params => {
      const cp = params.find(p => p.seriesName === 'ICP 200-Tick');
      if (!cp) return '';
      const idx = cp.dataIndex;
      const c   = candles[idx];
      if (!c) return '';
      const chg   = ((c.close - c.open) / c.open * 100).toFixed(2);
      const arrow = c.close >= c.open ? '\u25b2' : '\u25bc';
      const color = c.close >= c.open ? BULL : BEAR;
      const net   = c.buyVol - c.sellVol;
      const nc    = net >= 0 ? BULL : BEAR;
      const live  = c.isLive ? ' <span style="color:#aaa">\u25cf live ' + c.tickCount + '/200</span>' : '';
      const np    = npByCandle[idx] > 0
        ? '<br/><span style="color:' + NP_COLOR + '">\u25bc NP\u2192Exchange: ' + fmtICP(npByCandle[idx]) + ' ICP</span>'
        : '';
      return (
        '<b>' + new Date(c.tsMs).toISOString().slice(0,16).replace('T',' ') + ' UTC</b>' + live + '<br/>' +
        'O: ' + c.open.toFixed(4) + '  H: ' + c.high.toFixed(4) + '<br/>' +
        'L: ' + c.low.toFixed(4) + '  C: ' + c.close.toFixed(4) + '<br/>' +
        '<span style="color:' + color + '">' + arrow + ' ' + chg + '%</span>' +
        '  <span style="color:#aaa">\u23f1 ' + fmtDur(c.durationMs) + '</span><br/>' +
        'Buy: ' + (c.buyVol/1000).toFixed(1) + 'k  Sell: ' + (c.sellVol/1000).toFixed(1) + 'k  ' +
        '<span style="color:' + nc + '">' + (net>=0?'+':'') + (net/1000).toFixed(1) + 'k</span>' +
        np +
        (() => {
          const cv = cvdNorm[idx];
          const cc = cv >= 0 ? BULL : BEAR;
          const ls = largeSellsByCandle[idx];
          return (
            '\nCVD: <span style="color:' + cc + '">' + (cv>=0?'+':'') + (cv/1000).toFixed(1) + 'k</span>' +
            (ls > 0 ? '\n\ud83d\udd34 Large Sell: <b>' + fmtICP(ls) + ' ICP</b>' : '')
          );
        })()
      );
    }
  },
  series: [
    {
      name: 'ICP 200-Tick',
      type: 'candlestick',
      xAxisIndex: 0, yAxisIndex: 0,
      itemStyle: { color: BULL, color0: BEAR, borderColor: BULL, borderColor0: BEAR },
      data: candles.map(c => c.isLive
        ? { value: [c.open, c.close, c.low, c.high],
            itemStyle: { color: GREY, color0: GREY, borderColor: '#999', borderColor0: '#999' } }
        : [c.open, c.close, c.low, c.high]
      ),
      markLine: {
        silent: true, symbol: 'none', animation: false,
        data: flipLines
      },
      markArea: {
        silent: true,
        data: regimeAreas
      }
    },
    {
      name: 'NP\u2192Exchange',
      type: 'scatter',
      xAxisIndex: 0, yAxisIndex: 0,
      symbol: 'triangle',
      symbolRotate: 180,
      itemStyle: { color: NP_COLOR },
      label: {
        show: true,
        formatter: p => {
          const amt = npByCandle[p.dataIndex];
          return amt > 0 ? fmtICP(amt) : '';
        },
        position: 'top',
        color: NP_COLOR,
        fontSize: 9,
        fontWeight: 'bold'
      },
      data: candles.map((c, i) => {
        if (npByCandle[i] <= 0) return { value: [i, null], symbolSize: 0 };
        const size = Math.min(32, Math.max(8, Math.log10(npByCandle[i]) * 7));
        return { value: [i, c.high * 1.004], symbolSize: size };
      })
    },
    {
      name: 'Buy Vol',
      type: 'bar', xAxisIndex: 1, yAxisIndex: 1, stack: 'vol',
      data: candles.map(c => ({
        value: c.buyVol,
        itemStyle: { color: c.isLive ? 'rgba(38,166,154,0.3)' : 'rgba(38,166,154,0.65)' }
      })),
      barMaxWidth: 12
    },
    {
      name: 'Sell Vol',
      type: 'bar', xAxisIndex: 1, yAxisIndex: 1, stack: 'vol',
      data: candles.map(c => ({
        value: -c.sellVol,
        itemStyle: { color: c.isLive ? 'rgba(239,83,80,0.3)' : 'rgba(239,83,80,0.65)' }
      })),
      barMaxWidth: 12
    }
    ,
    {
      name: 'CVD',
      type: 'line',
      xAxisIndex: 1, yAxisIndex: 2,
      data: cvdNorm,
      lineStyle: { color: '#7986cb', width: 1.5 },
      itemStyle: { color: '#7986cb' },
      symbol: 'none',
      z: 10
    },
    {
      name: 'Large Sell',
      type: 'scatter',
      xAxisIndex: 0, yAxisIndex: 0,
      symbol: 'triangle',
      symbolRotate: 180,
      itemStyle: { color: '#ff1744', opacity: 0.9 },
      label: {
        show: true,
        formatter: p => {
          const qty = largeSellsByCandle[p.dataIndex];
          return qty > 0 ? fmtICP(qty) : '';
        },
        position: 'top',
        color: '#ff1744',
        fontSize: 9,
        fontWeight: 'bold'
      },
      data: candles.map((c, i) => {
        if (!largeSellsByCandle[i]) return { value: [i, null], symbolSize: 0 };
        const size = Math.min(22, Math.max(8, Math.log10(largeSellsByCandle[i]) * 6));
        return { value: [i, c.high * 1.006], symbolSize: size };
      })
    }
  ]
};
